import{_ as b,o as a,c as e,j as p,a as t,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const h=JSON.parse('{"title":"2.缝合兽","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/射击类/荒野猎人/永恒猎手/2.缝合兽.md","filePath":"4.资源分区/6.技艺及称号/射击类/荒野猎人/永恒猎手/2.缝合兽.md"}'),s={name:"4.资源分区/6.技艺及称号/射击类/荒野猎人/永恒猎手/2.缝合兽.md"};function o(d,r,_,l,D,i){return a(),e("div",null,[...r[0]||(r[0]=[p("h1",{id:"_2-缝合兽",tabindex:"-1"},[t("2.缝合兽 "),p("a",{class:"header-anchor",href:"#_2-缝合兽","aria-label":'Permalink to "2.缝合兽"'},"​")],-1),p("table",{class:"bannerparthead"},[p("tbody",null,[p("tr",{id:"hdr"},[p("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风023")])])],-1),n('<h1 id="缝合兽" tabindex="-1">缝合兽 <a class="header-anchor" href="#缝合兽" aria-label="Permalink to &quot;缝合兽&quot;">​</a></h1><p>【缝合兽】C+1000<br> 特异本质<br> 独立随从</p><p>属性<br> 生理属性<br> ■力量9<br> ■敏捷9<br> ■耐力11<br> 心智属性<br> ■智力6<br> ■感知11<br> ■决心6<br> 互动属性<br> ■风度6<br> ■操控9<br> ■沉着6</p><p>技能<br> 生理系<br> ■运动5-反射5<br> ■求生8-强韧8-动物沟通5<br> ■射击1<br> ■武技8-天生武器专业8（取决于你为其选择的尸块）</p><p>心智系<br> ■学识1<br> ■器用1<br> ■手艺1<br> ■专注5-意志5</p><p>互动系<br> ■洞察5-侦查5<br> ■隐秘5-潜藏5<br> ■表达1<br> ■社交1</p><p>衍生属性值<br> 体积 5<br> 速度 （力量【9】+敏捷【9】+体积【5】+每1点敏捷上的附加获得3移动速度）=26米<br> 先攻 （敏捷【9】+沉着【6】）=2D10+15<br> 防御 （敏捷感知的平均值【10】+较高者的附加成功【2】）= 10+2<br> 生命值 （耐力【11】+体积【5】+耐力附加【2 】×5）=26<br> 意志力池 （决心【6】+沉着【6】+决心附加【 1】×2）=14<br> 意志 （决心【6】+专注5+意志【5】）=17+3<br> 反射 （敏捷【9】+运动5+反射【5】）=20+3<br> 强韧 （耐力【11】+生存8+强韧【8】）=28+5<br> 侦查 （感知【11】+洞察5+侦查【5】）=22+5（缝合兽操控属性上附加成功对互动系技能的加成默认加在洞察技能上）<br> 敏感范围 （感知【11】*20米+感知上的附加成功【2 】*20米）=260米</p><p>关于属性上的附加成功：<br> 力量上的每1点附加成功会为其提供力量检定上的1DP增强加值与1点附加成功，可携带物品体积额外提升4点<br> 敏捷上的每1点附加成功会在回合开始时额外提供1点基础Ap并提高3米额外移速<br> 耐力上的每1点附加成功会为其提供5点生命值</p><p>智力上的每1点附加成功会为其提供每场景一次，在进行某个检定时可以将1个失败骰转为成功骰的能力，每有2点智力附加成功就能额外将一个失败骰转为成功骰，这一能力不能在一次检定中多次使用<br> 感知上的每1点附加成功会为其提供额外的20米敏感范围及洞察技能检定上的1点增强加值<br> 决心上的每1点附加成功会为其提供2点额外的意志池上限，每达到2点就会赠送2点专注技能检定上的增强加值</p><p>风度上的每1点附加成功会为其提供5点额外的外貌上升或者获得1点全检定上的机运加值，并额外提供社交/表达技能检定上的1点增强加值<br> 操控上的每1点附加成功会为其提供1点操控检定上的附加成功与所有互动技能检定上的1点表现加值<br> 沉着上的每1点附加成功会为其提供在先攻检定上的额外一个十面骰以及在进行短休息后额外恢复1点意志力</p><p>攻击预设：<br> 普通攻击预设：力量9+武技8+天生武器专业8=26+5</p><p>防御预设：基础防御10+2</p><p>性别：无性别，缝合兽已经失去了性别认知和性征器官</p><p>特性：</p><p>【尸块抉择】：缝合兽是由4种来自不同生物的尸块缝合而成的，这些尸块给缝合兽带来了不同的特性，通过永恒猎人自己的选择来为缝合兽搭配不同的特性，但永恒猎人不可为缝合兽选择完全相同尸块进行组合。在选择尸块时，永恒猎人至少需要为缝合兽选择一个躯干部位。若永恒猎人不为缝合兽选择头部，则该缝合兽失去独立随从特性。若永恒猎人不为缝合兽选择肢体部位，则该缝合兽移动速度减半。<br> 当永恒猎人已经为缝合兽选择完4种尸块后，若仍想为其缝合更多尸块，则每个尸块售价为1000点。<br> 缝合兽在攻击和防御时可以听其主人的指令来选择使用哪些肢体参与，参与这次行为的肢体所附带的特性可以同时触发，没参与行为的肢体所附带的特性则无法触发。</p><p>【拼凑的恐惧】：由各种不同尸块拼凑而出的缝合兽在视觉上的冲击力超越了许多传统恐怖的象征，或者说缝合兽就是他们的集合体。而当缝合兽击杀了一名敌人的时候，它独有的那种残忍手段搭配上渗人的外表会让周围目睹这一幕发生的敌对目标感到颤栗。</p><p>每当缝合兽击杀一个敌对目标时，会让其身周8米圆形范围内的敌人进行一次DC为12的意志豁免，若失败，则获得1点不可豁免的恐惧点数（影响心灵来源）。</p><p>装备位：</p><p>购买尸块记录：</p><p>【C级尸块列表】：</p><p>头部类：</p><p>【狮蝎之首】<br> 分类：头部</p><p>这是一枚来自于格林世界中狮蝎怪的首级，当有目标被狮蝎怪凝视时便会瑟瑟发抖，话语结巴，最终沦为它的食物。比起普通的狮子，它的首级外表收敛了一些野性，略有人形，只是对人类而言，这种相近于人的外貌，却更有震慑力。</p><p>缝合了该尸块的缝合兽在进行威吓检定时，获得3DP的表现加值。</p><p>【地府之牛】<br> 分类：头部</p><p>这是一枚产自于大话西游世界中牛头的首级，外形虽然很像普通牛头，但只要一呼气，就会刮起阴风阵阵。作为地府勾魂索命的使者，牛头对于魂魄拥有异常灵敏的感知。</p><p>缝合了该尸块的缝合兽具有灵感视觉和黑暗视觉。</p><p>【魔兽之犬】<br> 分类：头部</p><p>这是一枚产自于盾之勇者成名录世界中双头恶犬的首级，通体漆黑双目猩红，令村中冒险者闻风丧胆的矿洞守门人。</p><p>缝合了该尸块的缝合兽具有自动警觉能力，具有D级特异本质的侦测能力，在该缝合兽处于清醒状态下时对周围的环境时时刻刻进行侦查。</p><p>【蓝魔之首】<br> 分类：头部</p><p>这是一枚产自于Dota世界的双头食人魔法师的首级，皮肤呈深蓝色，有着外显的长獠牙和些许玄奥的魔法纹路。</p><p>缝合了该尸块的缝合兽可以自动学会双头食人魔法师的天赋法术：嗜血术。<br> 嗜血术：使用一个自由动作，令缝合怪获得攻击上的3DP增强加值，持续到本轮结束。</p><p>【接肢龙头】<br> 分类：头部/肢体-爪</p><p>这是一枚产自于艾尔登法环世界的接肢飞龙的头颅，皮肤干瘪，隐隐有火焰的光泽闪过，既可以作为头部缝合，也可以作为肢体缝合。</p><p>缝合了该尸块的缝合兽在进行攻击时可以获得3米的触及范围提升，且用该尸块进行攻击时造成的是火焰伤害。</p><p>【知识之树】<br> 分类：头部</p><p>这是一枚产自于魔兽争霸世界的知识古树的头颅，是采集自知识古树的中段脸庞部位，当眼睛和嘴巴闭上时，看起来就跟普通的树干没有区别。</p><p>缝合了该尸块的缝合兽在进行学识相关的检定时，获得3DP的修行加值。</p><p>【嗜血狼头】<br> 分类：头部</p><p>这是一枚产自于范海辛世界的狼人的头颅，其脸孔上的鬃毛呈现非常狂妄的姿态，口齿之间常有涎水滴落，在见到血迹之后双眼会立刻变红。</p><p>缝合了该尸块的缝合兽在战斗环节中，若有敌对目标在其身边因他人的攻击致使其流血，则该缝合兽立刻获得3DP攻击检定上的士气加值。</p><p>躯干类：</p><p>【恐龙之躯】<br> 分类：躯干</p><p>这是一具产自于恐龙战队世界的三角龙躯干，整体为人形，拥有壮硕的肌肉，饱满的肌群在运动时显得格外活跃。</p><p>缝合了该尸块的缝合兽获得3点天生防御。</p><p>【铠甲之躯】<br> 分类：躯干</p><p>这是一具产自于地下城与勇士世界的天之驱逐者的躯干，看上去仅是一副黄白色的人形铠甲，即便是将对方击败后也无法使铠甲从其躯干上剥除，故最后作为一个整体保存。</p><p>缝合了该尸块的缝合兽获得3点护甲防御。</p><p>【荆棘纠葛】<br> 分类：躯干</p><p>这是一具产自于英雄联盟世界的婕拉的躯干，是数条荆棘缠绕而成的植物，大体为绿色，尖端呈红色，欲有花瓣盛放。</p><p>缝合了该尸块的缝合兽可以与D级及以下的植物沟通交流，这是一个D级信息共享的能力，且在接触无支线的植物时，可以立刻获得对方的信息，这是一个无支线变形来源的解析能力。</p><p>【不死之躯】<br> 分类：躯干</p><p>这是一具产自于不死军团世界的木乃伊的躯干，表面看起来就是人类的躯干缠上了数不清的绷带，但实际上谁也没看到过这些尸块里是真的有尸体，还是只是绷带。</p><p>缝合了该尸块的缝合兽获得6点强韧豁免上的器械加值。</p><p>【黑夜之躯】<br> 分类：躯干</p><p>这是一具产自于吸血侠世界的吸血鬼的躯干，皮肤略显苍白，大体于人类无异，只有当你在上面轻轻划上一刀的时候才会知道，这种甚至已经失去了生命力躯体拥有如何强劲的恢复力。</p><p>缝合了该尸块的缝合兽获得1点快速医疗点数（医疗点20）。</p><p>【金刚之躯】<br> 分类：躯干</p><p>这是一具产自于变形金刚世界的机器蝙蝠的躯干，金属的泛冷色躯干，属于霸天虎的印记赫然其上。虽然在磁带金刚中是战斗力较弱的存在，但能够取得这样一份完整的尸块也实属不易。</p><p>缝合了该尸块的缝合兽自身敏感范围内出现了通过D级及以下网络传播的信息时，<br> 缝合怪用智力+器用+电脑操作来进行一次检定，对抗目标的智力+器用+电脑操作，成功则可得知传播信息的内容，这是一个D级的解析能力。<br> 并且该缝合兽还可以解锁无支线的电子设备，这是一个无支线级别的支配能力。</p><p>肢体类：</p><p>【丧尸之手】<br> 分类：肢体-拳</p><p>这是一对产自于生化危机世界里的暴君之手臂，肤色黯淡，血管暴凸，散发出一股令人作呕的腐臭气息。</p><p>缝合了该尸块的缝合兽，在进行肉搏攻击检定时，攻击时额外获得5点威猛，使用这对手臂进行攻击时造成钝击伤害。</p><p>【恶魔之爪】<br> 分类：肢体-爪</p><p>这是一对产自数码宝贝世界里的恶魔兽之手臂，通体漆黑，散发着不详的气息。</p><p>缝合了该尸块的缝合兽，在进行肉搏攻击检定时，额外获得5点破魔，使用这对手臂进行攻击时造成挥砍伤害。</p><p>【螳螂之刃】<br> 分类：肢体-爪</p><p>这是一对产自宝可梦世界里的飞天螳螂之手臂，通体青碧，前端并非手掌，取而代之的是一对镰刃。</p><p>缝合了该尸块的缝合兽，在进行肉搏攻击检定时，额外获得5点高速，使用这对手臂进行攻击时造成挥砍伤害。</p><p>【枭熊之拳】<br> 分类：肢体-爪</p><p>这是一对产自于DND世界里的枭熊之手臂，两臂粗壮，前端生有锐爪，具有极强的破坏力。</p><p>缝合了该尸块的缝合兽，在进行肉搏攻击检定时，额外获得5点破甲，使用这对手臂进行攻击时造成挥砍伤害。</p><p>【工匠之手】<br> 分类：肢体-拳</p><p>这是一对产自于魔兽世界里的地精之手臂，手臂纤长，手指灵活，并非肉搏作战时的好选择。</p><p>缝合了该尸块的缝合兽，在进行手艺检定时，获得3DP的技艺加值。使用这对手臂进行攻击时仅能造成冲击点数。</p><p>【猛毒之吻】<br> 分类：肢体-拳/尾</p><p>这是半截产自于毒蛇列车世界里的食肉毒蛇的前端，毒腺完整，蛇头灵动。此毒蛇生于玛雅人的诅咒，毒素猛烈可毙人于瞬息之间。</p><p>该部位既可作为手臂缝合，也可作为尾巴缝合。缝合了该尸块的缝合兽在进行肉搏攻击检定时，可以附带1点毒素点数（诅咒来源），正常豁免。使用该肢体进行攻击时造成穿刺伤害。</p><p>【紫晶之锤】<br> 分类：肢体-拳/尾</p><p>这是一条产自于怪物猎人世界里的尾晶蝎的尾巴，整体呈紫黑色，上面有厚重的盔甲覆盖，前端生有一块沉重的紫晶。</p><p>该部位既可作为手臂缝合，也可作为尾巴缝合。缝合了该尸块的缝合兽在进行肉搏格挡时，可以额外获得3点盔甲防御。使用该肢体进行攻击时造成钝击伤害。</p><p>【感应之触】<br> 分类：肢体-爪/腿</p><p>这是一对产自于火焰纹章世界里的巨蜘蛛的腿，整体为黑色，上面生长着细不可查的纤毛，对于任何一点波动都感知敏锐。</p><p>该部位既可作为手臂缝合，也可作为腿部缝合。缝合了该尸块的缝合兽在进行洞察检定时，可以额外获得3点器械加值。使用该肢体进行攻击时造成穿刺伤害。</p><p>【圣诞精灵】<br> 分类：肢体-腿</p><p>这是四条产自于圣诞列车世界里驯鹿的腿，通体覆盖着黄白色的柔软绒毛，腿部肌肉看上去强劲有力，足部的鹿蹄沉重又轻灵，正是它们在每个圣诞夜带着全世界的圣诞礼物飞驰于夜空。</p><p>缝合了该尸块的缝合兽，在行动时可以无视C级及以下困难地形，且获得5米的移动速度加值。</p><p>【人鱼之尾】<br> 分类：肢体-腿/尾</p><p>这是一条产自于海王世界的亚特兰蒂斯战士的腿，碧蓝色的鳞片覆盖了整个尸块，看着便如同大海的颜色一般。形状同故事里的人鱼尾巴一样，只是在陆地上时可以自由变形成普通人类的双腿模样。</p><p>缝合了该尸块的缝合兽拥有等同于基础速度的游泳速度，并且在陆上行动时该尸块会变回人类双腿的外形，这是一个无支线的变形能力。</p><p>【窃贼双足】<br> 分类：肢体-腿</p><p>这是一对产自于侏罗纪公园世界的窃蛋龙的双腿，肌肤颜色成黑褐色，肌肉紧实地附着其上，有着粗糙但清晰的皮肤纹理。</p><p>缝合了该尸块的缝合兽移动速度额外+20。</p><p>【无影无迹】<br> 分类：肢体-腿</p><p>这是一对产自于咒怨世界的伽椰子的双腿，其外观除了苍白以外，跟人类女性的双腿并无区别。</p><p>当缝合了该尸块的缝合怪进行移动时，身躯会从下至上逐渐变得透明，直至完全无法看到。<br> 这视为当该缝合怪进行主动移动行为时，获得D级特异本质的反侦测效果，<br> 但以此反侦测等级在进行侦测对抗时，即使对方在与受影响单位进行的侦测等级对抗与定位对抗中失败，也能模糊定位缝合兽。<br> 同时无视D级的困难地形。</p><p>【大地亲和】<br> 分类：肢体-尾巴</p><p>这是一条产自于古希腊神话世界的牛头人弥诺陶的尾巴，看起来是一条苍劲有力的短尾，当这条尾巴接触到地面的时候，会连通大地母亲，获得可以匹敌半神的力量。</p><p>缝合了该尸块的缝合兽，当尾巴可以触碰到地面时（必须是真正的大地，不能是船舱地板，高楼地板等），在进行力量相关检定时获得1dp的增强加值和1点附加成功。</p><p>【桃粉之尾】<br> 分类：肢体-尾巴</p><p>这是一条产自于山海经世界的陵鱼的尾巴，尾部鳞片熠熠生辉，每当主体喝酒至微醺时，便会散发出桃红色的微光，看起来宛如桃花，美丽非常。</p><p>缝合了该尸块的缝合兽，每当喝过酒之后，尾部都会发出桃粉色的光，并获得5点外貌值的提升。</p><p>【夔兽之足】<br> 分类：肢体-腿/尾巴</p><p>这是一条产自于蚩尤之战世界的夔兽之足，夔兽仅有单足，既可以作足，也可以作尾。夔兽之腿看起来粗壮有力，足分两趾，踏地时如有雷鸣。</p><p>缝合了该尸块的缝合兽，当踏足于大地的时候，潜藏检定自动视作失败。该缝合兽移动时经过的地面会成为D级的困难地形，并在移动速度上+5。</p><p>【缝合怪】B+2000或由【缝合兽】支付差价提升为【缝合怪】<br> 特异本质<br> 独立随从</p><p>属性<br> 生理属性<br> ■力量14<br> ■敏捷14<br> ■耐力16<br> 心智属性<br> ■智力11<br> ■感知16<br> ■决心11<br> 互动属性<br> ■风度11<br> ■操控14<br> ■沉着11</p><p>技能<br> 生理系<br> ■运动8-反射8<br> ■求生11-强韧11-动物沟通8<br> ■射击1<br> ■武技11-天生武器专业11（取决于你选择的尸块）</p><p>心智系<br> ■学识1<br> ■器用1<br> ■手艺1<br> ■专注8-意志8</p><p>互动系<br> ■洞察8-侦查8<br> ■隐秘8-潜藏8<br> ■表达1<br> ■社交1</p><p>衍生属性值<br> 体积 5<br> 速度 （力量【14】+敏捷【14】+体积【5】+每1点敏捷上的附加获得3移动速度）=40米<br> 先攻 （敏捷【14】+沉着【11】）=3D10+25<br> 防御 （敏捷感知的平均值【15】+较高者的附加成功【3】）=15+3<br> 生命值 （耐力【16】+体积【5】+耐力附加【3 】×5）=37<br> 意志力池 （决心【11】+沉着【11】+决心附加【2 】×2）=26<br> 意志 （决心【11】+专注8+意志【8】）=31+5<br> 反射 （敏捷【14】+运动8+反射【8】）=32+5<br> 强韧 （耐力【16】+生存11+强韧【11】）=40+7<br> 侦查 （感知【16】+洞察8+侦查【8】）=34+8（缝合怪操控上的附加成功默认加值为洞察技能）<br> 敏感范围 （感知【16】*20米+感知上的附加成功【3 】*20米）=380米</p><p>关于属性上的附加成功：<br> 力量上的每1点附加成功会为其提供力量检定上的1DP增强加值与1点附加成功，可携带物品体积额外提升4点<br> 敏捷上的每1点附加成功会在回合开始时额外提供1点基础Ap并提高3米额外移速<br> 耐力上的每1点附加成功会为其提供5点生命值</p><p>智力上的每1点附加成功会为其提供每场景一次，在进行某个检定时可以将1个失败骰转为成功骰的能力，每有2点智力附加成功就能额外将一个失败骰转为成功骰，这一能力不能在一次检定中多次使用<br> 感知上的每1点附加成功会为其提供额外的20米敏感范围及洞察技能检定上的1点增强加值<br> 决心上的每1点附加成功会为其提供2点额外的意志池上限，每达到2点就会赠送2点专注技能检定上的增强加值</p><p>风度上的每1点附加成功会为其提供5点额外的外貌上升或者获得1点全检定上的机运加值，并额外提供社交/表达技能检定上的1点增强加值<br> 操控上的每1点附加成功会为其提供1点操控检定上的附加成功与所有互动技能检定上的1点表现加值<br> 沉着上的每1点附加成功会为其提供在先攻检定上的额外一个十面骰以及在进行短休息后额外恢复1点意志力</p><p>攻击预设：<br> 普通攻击预设：力量14+武技11+专业11=38+8</p><p>防御预设：基础防御15+3</p><p>性别：无性别，缝合兽已经失去了性别认知和性征器官</p><p>特性：</p><p>【提升：尸块抉择】：<br> 晋升为缝合怪的缝合兽，除了原本在C级时选择的尸块保留外，还可以额外选择一个B级列表中的尸块进行缝合。若在已经选定了B级尸块进行缝合后仍想继续缝合，则每个B级尸块需要支付C+2000来进行缝合。</p><p>【提升：拼凑的恐惧】：<br> 晋升为缝合怪的缝合兽，在击杀一名敌人后，其身周8米范围内的敌人所承受的意志豁免检定DC提升为14。</p><p>装备位：</p><p>购买尸块记录：</p><p>B级尸块列表：</p><p>头部类：</p><p>【塞壬之首】<br> 分类：头部</p><p>这是一颗产自于奥德修斯传说世界的海妖塞壬的头颅，看上去是一个长相为美人的首级，但实际上美丽的外表仅是伪装，隐藏在表象下的尖刺才是真实的塞壬。尤其是她根植在基因里的音乐天赋，更是连大英雄奥德修斯都难以抵抗。</p><p>缝合了该尸块的缝合怪，获得7点外貌值提升，并且当该缝合怪在进行攻击检定时，可附带四分之一的魅惑异常点数（幻象来源），标准豁免。</p><p>【蚩尤之首】<br> 分类：头部</p><p>这是一颗产自于山海经世界的蚩尤的首级，头上生有尖利的角，耳朵旁边的毛发直竖起来好像剑戟。</p><p>缝合了该尸块的缝合怪，全部身躯都会因受到蚩尤血统的侵染，变为铜头铁骨，获得5点天生防御，以及基于天生防御的【坚韧】特性。</p><p>【地狱之声】<br> 分类：头部</p><p>这是三颗产自于埃涅阿斯纪世界的地狱三头犬刻耳柏洛斯的头颅，它们的三个喉咙完全同频，因此在吼叫时发出的声音便是大名鼎鼎的地狱三重奏。外表看起来只是三颗如平常恶犬一般的头颅，只有当那种地狱之声从它们口中响起时，那种恐惧的战栗感才会让每个人理解什么是地狱看门犬。</p><p>缝合了该尸块的缝合怪，获得5点感知检定上的增强加值，并且当该缝合怪进行攻击检定时，可附带四分之一的恐惧异常点数（影响心灵来源），标准豁免。</p><p>躯干类：</p><p>【英招之巡】<br> 分类：躯干</p><p>这是一具产自于伏羲传世界中的英招的躯干，英招为天神，背生双翅，人脸马身。是在黄帝治时，负责管理黄帝天庭下“悬圃”的天神。整日里不是天马行空便是周游四海，巡视天下，甚是威风。</p><p>缝合了该尸块的缝合怪获得9点洞察防御。</p><p>【巨狼后裔】<br> 分类：躯干</p><p>这是一具产自于散文埃达世界中哈提的躯干，哈提为魔狼，是在夜空中追逐月亮的巨狼。传说在末日之时，巨狼哈提将吞下月亮，便如其父芬里尔吞噬奥丁一般。其躯体壮硕，毛发银亮，在月光的照耀下更显威风。</p><p>缝合了该尸块的缝合怪获得2点体积增长，5点外貌增长，并获得1点快速医疗点数（医疗点12）。</p><p>【尘世巨蟒】<br> 分类：躯干</p><p>这是一具产自于诸神的黄昏世界中耶梦加德的躯干，耶梦加德是一条巨大的海蛇，拥有比一般的神明还要恐怖的邪恶力量。但其却拥有一个一生的宿敌――雷神托尔。在诸神黄昏的最后一战中，耶梦加德拼尽全力，将能够弑神的毒液注入到雷神托尔的体内，却也被雷神之锤击中头颅而死，最终双方同归于尽，可它的恶名却流传至今。<br> 耶梦加德的躯干看着与寻常的巨蟒之身并无差别，只有靠近仔细观察才能看到其上玄奥的符文。蛇鳞撞击之时隐隐能听见嘶嘶声，亦如蛇语。</p><p>缝合了该尸块的缝合怪获得6点雷电易伤，并获得9点盔甲防御以及1点基于盔甲防御的附加成功。</p><p>肢体类：</p><p>【达贡之力】<br> 分类：肢体-手臂</p><p>这是一对产自于印斯茅斯世界中达贡的手臂，达贡之巨力在克苏鲁世界观中举世闻名，其双臂臂上生有灰色的巨鳞，反关节处长有巨鳍，肌肉体积极大，挥舞时会发出有节奏的巨响。</p><p>缝合了该尸块的缝合怪在进行力量检定时获得4点附加成功，这是增强加值。</p><p>【神主坐骑】<br> 分类：肢体-腿</p><p>这是一对产自于北欧神话世界中斯雷普尼尔的腿，斯雷普尼尔是主神奥丁的坐骑，是一匹拥有八足的神马，被称为最优秀的马匹，不过永恒猎人们只猎取到其中两足。<br> 斯雷普尼尔的腿通体洁白，拥有最适合奔跑的肌肉曲线，看着便觉得赏心悦目。</p><p>缝合了该尸块的缝合怪在每轮行动开始前，额外进行一次移动。</p><p>【神官之尾】<br> 分类：肢体-尾巴</p><p>这是九条产自于《诗大雅皇矣》中神官陆吾之尾，陆吾为黄帝下属天神之一，人面虎身，拥有九条尾巴。陆吾负责掌管昆仑山上黄帝的行宫以及天上九城的部界。<br> 这九条尾巴即便已经从它们的主人身上分离，却依然生机灵动仿若有神之物。</p><p>缝合了该尸块的缝合怪获得基于天生防御的【超级坚韧】特性。</p><p>【星间双翼】<br> 分类：肢体-翅膀</p><p>这是一对产自于克苏鲁神话世界中拜亚基的翅膀，拜亚基被称为星间骏马，但实则是相貌极为恐怖的怪物。这一对翅膀有着分段的结构，有蝙蝠般的根部，昆虫型的中段以及鸟类的前端，但整体无毛发和皮肤，看起来便是血肉直接暴露在空气中。</p><p>缝合了该尸块的缝合怪获得完美机动性的飞行能力。</p><hr><p>Copyright ? 2024 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',160)])])}const f=b(s,[["render",o]]);export{h as __pageData,f as default};
